ruleSearch.bookList:
@js:(function(){
  try {
    var data = JSON.parse(result);
    var items = data.data?.list || data.result?.list || [];
    var bookList = [];

    for (var i = 0; i < items.length; i++) {
      var item = items[i];
      var link = item.url || item.link || '';

      if (!link.includes('m.libahao.com/book/')) continue;

      var title = item.title || item.name || '';
      title = title
        .replace(/^\s*【[^】]*】\s*/, '')
        .replace(/\s*-\s*篱笆好文.*$/, '')
        .replace(/\s*最新章节.*$/, '')
        .trim();

      bookList.push({
        name: title,
        url: link.split('?')[0],
        author: item.author || '',
        intro: item.description || item.abstract || '',
        cover: item.cover || item.image || ''
      });
    }
    return bookList;
  } catch(e) {
    return [];
  }
})()

